// Data Processing & KPI Calculation
const salesData = $input.first().json;
const marketingData = $('Fetch Marketing Data').first().json;
const externalMetrics = $('Fetch External Metrics').first().json;

// Calculate KPIs
const totalRevenue = salesData.reduce((sum, row) => sum + parseFloat(row.revenue || 0), 0);
const totalOrders = salesData.length;
const avgOrderValue = totalRevenue / totalOrders;
const conversionRate = (marketingData.conversions / marketingData.visitors * 100).toFixed(2);
const customerAcquisitionCost = marketingData.spend / marketingData.conversions;
const roi = ((totalRevenue - marketingData.spend) / marketingData.spend * 100).toFixed(2);

return [{
  json: {
    kpis: {
      total_revenue: totalRevenue,
      total_orders: totalOrders,
      avg_order_value: avgOrderValue.toFixed(2),
      conversion_rate: conversionRate,
      customer_acquisition_cost: customerAcquisitionCost.toFixed(2),
      roi: roi,
      period: 'Weekly'
    },
    sales_data: salesData,
    marketing_data: marketingData,
    external_metrics: externalMetrics
  }
}];

